    connection = get_database_connection()

    with connection.cursor() as cursor:
        query = "INSERT INTO redlines (contract_id, clause_text, suggested_change, playbook_rule_id, rationale, diff) VALUES (%s, %s, %s, %s, %s, %s)"

        diff = generate_diff(clause_text, suggested_change)

        cursor.execute(query, (contract_id, clause_text, suggested_change, playbook_rule_id, rationale, diff))

    connection.commit()

