def apply_playbook_rules(clause_text):
    session = Session(bind=engine)

    rules = session.query(PlaybookRule).all()
    precedences = session.query(RulePrecedence).order_by(RulePrecedence.priority.asc()).all()

    for precedence in precedences:
        rule = next((r for r in rules if r.id == precedence.playbook_rule_id), None)

        if rule and re.search(rule.clause_pattern, clause_text, re.IGNORECASE):
            return {
                "clause_text": clause_text,
                "suggested_change": rule.suggested_change,
                "playbook_rule_id": rule.id,
                "rationale": rule.rationale
            }

    session.close()
    return None

