def generate_redline_suggestions(clauses, playbook_rules):
    redlines = []

    for clause in clauses:
        for rule in playbook_rules:
            if match_conditions(rule['conditions'], clause.text):
                suggested_change = generate_suggested_change(rule)
                redlines.append({
