def get_similar_clauses(es, query):
    response = es.search(
        index="clauses",
        body={
            "query": {
                "bool": {
                    "must": [
                        {"match_phrase": {"clause_text": query}},
                        {"term": {"legal_risk_level": "HIGH"}}
                    ],
                    "should": [
                        {"match": {"contract_type": "Service Agreement"}},
                        {"match": {"industry_sector": "Technology"}}
                    ]
                }
            },
            "_source": ["clause_text", "legal_risk_level", "document_id"]
        }
    )

    return response['hits']['hits']

